// Normalize ANY uploaded source into a binary the document loader accepts.
//  - Database exports of every flavour (.sql from MySQL/Postgres/SQLite/MSSQL,
//    .csv, .tsv, .json, .ndjson, .xml, .yaml, .log ...) are text — force
//    mimeType text/plain so the auto loader always parses them.
//  - PDF/DOCX keep their real mime types (dedicated loaders handle them).
//  - The binary key is standardized to `file` regardless of what the form
//    field or n8n version named it.
//  - URL-only ingests (body.url, no file) are fetched here and passed on
//    as a text binary.
const item = $input.first();
const body = item.json.body ?? {};
const TEXT_EXTS = ['sql','csv','tsv','json','ndjson','txt','md','markdown','xml','yml','yaml','log','ini','conf','tql','cql','dump'];

const binKeys = Object.keys(item.binary ?? {});

if (binKeys.length > 0) {
  const bin = item.binary[binKeys[0]];
  const name = String(bin.fileName ?? '').toLowerCase();
  const ext = name.includes('.') ? name.split('.').pop() : '';
  if (TEXT_EXTS.includes(ext) || !bin.mimeType || bin.mimeType === 'application/octet-stream') {
    // Unknown/octet-stream mimes are overwhelmingly text exports — treat as text
    // unless clearly a binary doc format.
    if (!['pdf','docx','doc','xlsx','xls'].includes(ext)) {
      bin.mimeType = 'text/plain';
    }
  }
  return [{ json: item.json, binary: { file: bin } }];
}

if (body.url) {
  const res = await this.helpers.httpRequest({
    url: String(body.url),
    method: 'GET',
    returnFullResponse: false,
    encoding: 'text',
    timeout: 20000,
  });
  const text = typeof res === 'string' ? res : JSON.stringify(res);
  // Strip HTML tags so pages index as readable text
  const cleaned = text.replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<[^>]+>/g, ' ').replace(/\s{2,}/g, ' ').trim();
  const buffer = Buffer.from(cleaned, 'utf-8');
  const bin = await this.helpers.prepareBinaryData(buffer, 'page.txt', 'text/plain');
  return [{ json: item.json, binary: { file: bin } }];
}

throw new Error('No file or url in ingest payload');
